//+------------------------------------------------------------------+
//|                        Donchian_EA_v1.0.mq4                      |
//|                    Estrategia: Canal de Donchian                  |
//|                    Versión: 1.0 — Núcleo Base                     |
//|   Propósito: Optimización IS/OOS + CSV Export para análisis       |
//+------------------------------------------------------------------+
#property strict
#property copyright "Jose - FundedNext Development"
#property version   "1.00"

//+------------------------------------------------------------------+
//|  PARÁMETROS DE ENTRADA (todos optimizables en Strategy Tester)   |
//+------------------------------------------------------------------+

// --- Canal de Donchian ---
input int    DonchianPeriod   = 20;      // Periodos del canal (rango: 10-60)

// --- ATR para SL y TP dinámicos ---
input int    ATRPeriod        = 14;      // Periodos del ATR
input double ATRMultiplierSL  = 2.0;    // Multiplicador ATR para Stop Loss
input double ATRMultiplierTP  = 3.0;    // Multiplicador ATR para Take Profit

// --- Gestión de riesgo ---
input double RiskPercent      = 1.0;    // % de la cuenta a arriesgar por trade
input double MaxLotSize       = 5.0;    // Lote máximo permitido (FundedNext)

// --- Filtro horario (sesión) ---
input bool   UseSessionFilter = true;   // Activar filtro de sesión
input int    SessionStartHour = 8;      // Hora inicio sesión (GMT)
input int    SessionEndHour   = 20;     // Hora fin sesión (GMT)

// --- Protección de cuenta (FundedNext) ---
input double MaxDailyDrawdown = 4.0;    // DD diario máximo % antes de detener EA
input double MaxTotalDrawdown = 8.0;    // DD total máximo % antes de detener EA

// --- CSV Export ---
input bool   GenerateCSV      = true;   // Activar exportación de resultados a CSV

// --- Control de dirección ---
input bool   EnableBuy        = true;   // Permitir operaciones BUY
input bool   EnableSell       = true;   // Permitir operaciones SELL

// --- Magic Number (identificador único del EA) ---
input int    MagicNumber      = 202501; // Número mágico del EA

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                               |
//+------------------------------------------------------------------+
string   g_csvFileName   = "";          // Nombre del archivo CSV
double   g_startBalance  = 0;           // Balance al inicio del día
double   g_initBalance   = 0;           // Balance inicial de la sesión
datetime g_lastDayCheck  = 0;           // Control para reset diario
bool     g_eaEnabled     = true;        // Flag de protección activo

//+------------------------------------------------------------------+
//|  FUNCIÓN DE INICIALIZACIÓN                                        |
//+------------------------------------------------------------------+
int OnInit()
{
   // Guardar balance inicial
   g_initBalance  = AccountBalance();
   g_startBalance = AccountBalance();
   g_lastDayCheck = TimeCurrent();

   // Crear nombre del CSV: Donchian_EURUSD_M15_20250331.csv
   if(GenerateCSV)
   {
      g_csvFileName = StringFormat("Donchian_%s_%s_%s.csv",
                                   Symbol(),
                                   PeriodToString(Period()),
                                   TimeToString(TimeCurrent(), TIME_DATE));
      // Eliminar caracteres no válidos en nombre de archivo
      StringReplace(g_csvFileName, ":", "-");
      StringReplace(g_csvFileName, " ", "_");

      // Crear archivo y escribir cabecera
      int fileHandle = FileOpen(g_csvFileName, FILE_WRITE | FILE_CSV | FILE_ANSI);
      if(fileHandle != INVALID_HANDLE)
      {
         FileWrite(fileHandle,
                   "Ticker", "Timeframe", "FechaHoraApertura", "FechaHoraCierre",
                   "TipoOrden", "PrecioEntrada", "StopLoss", "TakeProfit",
                   "PrecioSalida", "ProfitPips", "ProfitUSD",
                   "BalancePosterior", "DrawdownPct", "Comentario");
         FileClose(fileHandle);
         Print("CSV creado: ", g_csvFileName);
      }
      else
      {
         Print("ERROR: No se pudo crear el archivo CSV. Código: ", GetLastError());
      }
   }

   Print("=== Donchian EA v1.0 Iniciado ===");
   Print("Símbolo: ", Symbol(), " | Timeframe: ", PeriodToString(Period()));
   Print("Donchian Period: ", DonchianPeriod, " | ATR SL: x", ATRMultiplierSL, " | ATR TP: x", ATRMultiplierTP);

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//|  FUNCIÓN PRINCIPAL — Se ejecuta en cada tick                      |
//+------------------------------------------------------------------+
void OnTick()
{
   // --- Verificar protecciones de cuenta ---
   if(!g_eaEnabled) return;
   if(!CheckDrawdownLimits()) return;

   // --- Ejecutar solo en vela nueva (evita múltiples entradas en el mismo tick) ---
   static datetime lastBarTime = 0;
   if(Time[0] == lastBarTime) return;
   lastBarTime = Time[0];

   // --- Verificar filtro de sesión ---
   if(UseSessionFilter && !IsSessionActive()) return;

   // --- Verificar si ya hay una posición abierta de este EA ---
   if(HasOpenPosition()) return;

   // --- Calcular valores del Canal de Donchian (en la vela anterior, index=1) ---
   double upperBand = GetDonchianHigh(DonchianPeriod);
   double lowerBand = GetDonchianLow(DonchianPeriod);

   // --- Calcular ATR para SL y TP ---
   double atrValue = iATR(NULL, 0, ATRPeriod, 1);
   if(atrValue <= 0) return;

   double slPoints = atrValue * ATRMultiplierSL;
   double tpPoints = atrValue * ATRMultiplierTP;

   // --- Precio actual ---
   double askPrice = Ask;
   double bidPrice = Bid;

   // --- SEÑAL DE COMPRA: precio rompe por encima de la banda superior ---
   // La vela anterior cerró por encima del máximo de los N periodos previos
   if(EnableBuy && Close[1] > upperBand)
   {
      double sl  = askPrice - slPoints;
      double tp  = askPrice + tpPoints;
      double lot = CalculateLotSize(slPoints);

      if(lot > 0)
      {
         int ticket = OrderSend(Symbol(), OP_BUY, lot, askPrice, 3,
                                NormalizeDouble(sl, Digits),
                                NormalizeDouble(tp, Digits),
                                "Donchian_BUY", MagicNumber, 0, clrBlue);
         if(ticket > 0)
            Print("BUY abierto | Ticket:", ticket, " Lot:", lot,
                  " SL:", sl, " TP:", tp);
         else
            Print("ERROR al abrir BUY: ", GetLastError());
      }
   }

   // --- SEÑAL DE VENTA: precio rompe por debajo de la banda inferior ---
   else if(EnableSell && Close[1] < lowerBand)
   {
      double sl  = bidPrice + slPoints;
      double tp  = bidPrice - tpPoints;
      double lot = CalculateLotSize(slPoints);

      if(lot > 0)
      {
         int ticket = OrderSend(Symbol(), OP_SELL, lot, bidPrice, 3,
                                NormalizeDouble(sl, Digits),
                                NormalizeDouble(tp, Digits),
                                "Donchian_SELL", MagicNumber, 0, clrRed);
         if(ticket > 0)
            Print("SELL abierto | Ticket:", ticket, " Lot:", lot,
                  " SL:", sl, " TP:", tp);
         else
            Print("ERROR al abrir SELL: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//|  EVENTO: Orden cerrada — registrar en CSV                         |
//+------------------------------------------------------------------+
void OnTrade()
{
   if(!GenerateCSV) return;

   // Revisar historial de órdenes cerradas recientemente
   for(int i = OrdersHistoryTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_HISTORY)) continue;
      if(OrderMagicNumber() != MagicNumber)             continue;
      if(OrderSymbol() != Symbol())                     continue;

      // Solo procesar órdenes cerradas en este tick (cerradas hace menos de 5 seg)
      if(TimeCurrent() - OrderCloseTime() > 5)          continue;

      // Calcular profit en pips
      double pipSize    = (Digits == 5 || Digits == 3) ? 0.0001 : 0.001;
      double profitPips = 0;

      if(OrderType() == OP_BUY)
         profitPips = (OrderClosePrice() - OrderOpenPrice()) / pipSize;
      else if(OrderType() == OP_SELL)
         profitPips = (OrderOpenPrice() - OrderClosePrice()) / pipSize;

      // Calcular drawdown actual
      double ddPct = ((g_initBalance - AccountEquity()) / g_initBalance) * 100.0;
      if(ddPct < 0) ddPct = 0;

      // Escribir línea en CSV
      WriteCSVLine(OrderOpenTime(),
                   OrderCloseTime(),
                   OrderType(),
                   OrderOpenPrice(),
                   OrderStopLoss(),
                   OrderTakeProfit(),
                   OrderClosePrice(),
                   profitPips,
                   OrderProfit() + OrderSwap() + OrderCommission(),
                   AccountBalance(),
                   ddPct,
                   OrderComment());
   }
}

//+------------------------------------------------------------------+
//|  CALCULAR TAMAÑO DE LOTE basado en % de riesgo y SL en puntos    |
//+------------------------------------------------------------------+
double CalculateLotSize(double slDistance)
{
   if(slDistance <= 0) return(0);

   double accountBalance = AccountBalance();
   double riskAmount     = accountBalance * (RiskPercent / 100.0);
   double tickValue      = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize       = MarketInfo(Symbol(), MODE_TICKSIZE);
   double lotStep        = MarketInfo(Symbol(), MODE_LOTSTEP);
   double minLot         = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot         = MathMin(MarketInfo(Symbol(), MODE_MAXLOT), MaxLotSize);

   if(tickValue <= 0 || tickSize <= 0) return(0);

   // Fórmula: Lote = RiesgoUSD / (SL_distancia / tickSize * tickValue)
   double lotSize = riskAmount / ((slDistance / tickSize) * tickValue);

   // Redondear al step permitido
   lotSize = MathFloor(lotSize / lotStep) * lotStep;

   // Aplicar límites
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return(NormalizeDouble(lotSize, 2));
}

//+------------------------------------------------------------------+
//|  OBTENER MÁXIMO DE DONCHIAN (banda superior)                      |
//|  Usa barra index=1 como referencia (vela cerrada anterior)        |
//+------------------------------------------------------------------+
double GetDonchianHigh(int period)
{
   // iHighest devuelve el índice de la vela más alta en N periodos
   // Empezamos desde index=1 para no incluir la vela actual (abierta)
   int highestBar = iHighest(NULL, 0, MODE_HIGH, period, 1);
   return High[highestBar];
}

//+------------------------------------------------------------------+
//|  OBTENER MÍNIMO DE DONCHIAN (banda inferior)                      |
//+------------------------------------------------------------------+
double GetDonchianLow(int period)
{
   int lowestBar = iLowest(NULL, 0, MODE_LOW, period, 1);
   return Low[lowestBar];
}

//+------------------------------------------------------------------+
//|  VERIFICAR SI HAY POSICIÓN ABIERTA DE ESTE EA                     |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;
      if(OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol())
         return(true);
   }
   return(false);
}

//+------------------------------------------------------------------+
//|  VERIFICAR LÍMITES DE DRAWDOWN (protección FundedNext)            |
//+------------------------------------------------------------------+
bool CheckDrawdownLimits()
{
   // Reset diario del balance de referencia
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   MqlDateTime dtLast;
   TimeToStruct(g_lastDayCheck, dtLast);

   if(dt.day != dtLast.day)
   {
      g_startBalance = AccountBalance();
      g_lastDayCheck = TimeCurrent();
   }

   // DD diario
   double dailyDD = ((g_startBalance - AccountEquity()) / g_startBalance) * 100.0;
   if(dailyDD >= MaxDailyDrawdown)
   {
      if(g_eaEnabled)
      {
         g_eaEnabled = false;
         Print("⚠️ EA DETENIDO: Daily Drawdown alcanzado (", DoubleToString(dailyDD, 2), "%)");
         CloseAllPositions();
      }
      return(false);
   }

   // DD total
   double totalDD = ((g_initBalance - AccountEquity()) / g_initBalance) * 100.0;
   if(totalDD >= MaxTotalDrawdown)
   {
      if(g_eaEnabled)
      {
         g_eaEnabled = false;
         Print("⚠️ EA DETENIDO: Total Drawdown alcanzado (", DoubleToString(totalDD, 2), "%)");
         CloseAllPositions();
      }
      return(false);
   }

   return(true);
}

//+------------------------------------------------------------------+
//|  CERRAR TODAS LAS POSICIONES ABIERTAS                             |
//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;
      if(OrderMagicNumber() != MagicNumber)           continue;
      if(OrderSymbol() != Symbol())                   continue;

      double closePrice = (OrderType() == OP_BUY) ? Bid : Ask;
      bool   result     = OrderClose(OrderTicket(), OrderLots(), closePrice, 3, clrOrange);

      if(!result)
         Print("ERROR al cerrar orden #", OrderTicket(), ": ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//|  VERIFICAR SI ESTAMOS EN SESIÓN ACTIVA                            |
//+------------------------------------------------------------------+
bool IsSessionActive()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int currentHour = dt.hour;
   return(currentHour >= SessionStartHour && currentHour < SessionEndHour);
}

//+------------------------------------------------------------------+
//|  ESCRIBIR LÍNEA EN EL ARCHIVO CSV                                 |
//+------------------------------------------------------------------+
void WriteCSVLine(datetime openTime,
                  datetime closeTime,
                  int      orderType,
                  double   openPrice,
                  double   sl,
                  double   tp,
                  double   closePrice,
                  double   profitPips,
                  double   profitUSD,
                  double   balance,
                  double   ddPct,
                  string   comment)
{
   int fileHandle = FileOpen(g_csvFileName, FILE_READ | FILE_WRITE | FILE_CSV | FILE_ANSI);
   if(fileHandle == INVALID_HANDLE)
   {
      Print("ERROR al abrir CSV para escritura: ", GetLastError());
      return;
   }

   // Moverse al final del archivo
   FileSeek(fileHandle, 0, SEEK_END);

   string orderTypeStr = (orderType == OP_BUY) ? "BUY" : "SELL";
   string timeframeStr = PeriodToString(Period());

   FileWrite(fileHandle,
             Symbol(),
             timeframeStr,
             TimeToString(openTime,  TIME_DATE | TIME_MINUTES),
             TimeToString(closeTime, TIME_DATE | TIME_MINUTES),
             orderTypeStr,
             DoubleToString(openPrice,  Digits),
             DoubleToString(sl,         Digits),
             DoubleToString(tp,         Digits),
             DoubleToString(closePrice, Digits),
             DoubleToString(profitPips, 1),
             DoubleToString(profitUSD,  2),
             DoubleToString(balance,    2),
             DoubleToString(ddPct,      2),
             comment);

   FileClose(fileHandle);
}

//+------------------------------------------------------------------+
//|  CONVERTIR PERÍODO A STRING                                       |
//+------------------------------------------------------------------+
string PeriodToString(int period)
{
   switch(period)
   {
      case PERIOD_M1:  return("M1");
      case PERIOD_M5:  return("M5");
      case PERIOD_M15: return("M15");
      case PERIOD_M30: return("M30");
      case PERIOD_H1:  return("H1");
      case PERIOD_H4:  return("H4");
      case PERIOD_D1:  return("D1");
      default:         return("CUSTOM");
   }
}

//+------------------------------------------------------------------+
//|  DESINICIALIZACIÓN                                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   Print("=== Donchian EA v1.0 Detenido ===");
   Print("Balance final: ", AccountBalance());
   Print("CSV guardado en: ", g_csvFileName);
}
//+------------------------------------------------------------------+

