   if(HasOpenPosition()) return;

   // --- Calcular valores del Canal de Donchian (en la vela anterior, index=1) ---
   double upperBand = GetDonchianHigh(DonchianPeriod);
   double lowerBand = GetDonchianLow(DonchianPeriod);

   // --- Calcular ATR para SL y TP ---
   double atrValue = iATR(NULL, 0, ATRPeriod, 1);
   if(atrValue <= 0) return;

   double slPoints = atrValue * ATRMultiplierSL;
   double tpPoints = atrValue * ATRMultiplierTP;

