      {
         int ticket = OrderSend(Symbol(), OP_SELL, lot, bidPrice, 3,
                                NormalizeDouble(sl, Digits),
                                NormalizeDouble(tp, Digits),
                                "Donchian_SELL", MagicNumber, 0, clrRed);
         if(ticket > 0)
            Print("SELL abierto | Ticket:", ticket, " Lot:", lot,
                  " SL:", sl, " TP:", tp);
         else
            Print("ERROR al abrir SELL: ", GetLastError());
      }
   }
