      if(TimeCurrent() - OrderCloseTime() > 5)          continue;

      // Calcular profit en pips
      double pipSize    = (Digits == 5 || Digits == 3) ? 0.0001 : 0.001;
      double profitPips = 0;

      if(OrderType() == OP_BUY)
         profitPips = (OrderClosePrice() - OrderOpenPrice()) / pipSize;
      else if(OrderType() == OP_SELL)
         profitPips = (OrderOpenPrice() - OrderClosePrice()) / pipSize;

      // Calcular drawdown actual
      double ddPct = ((g_initBalance - AccountEquity()) / g_initBalance) * 100.0;
      if(ddPct < 0) ddPct = 0;

      // Escribir línea en CSV
      WriteCSVLine(OrderOpenTime(),
                   OrderCloseTime(),
                   OrderType(),
                   OrderOpenPrice(),
                   OrderStopLoss(),
                   OrderTakeProfit(),
                   OrderClosePrice(),
                   profitPips,
                   OrderProfit() + OrderSwap() + OrderCommission(),
                   AccountBalance(),
                   ddPct,
                   OrderComment());
   }
}

//+------------------------------------------------------------------+
//|  CALCULAR TAMAÑO DE LOTE basado en % de riesgo y SL en puntos    |
//+------------------------------------------------------------------+
double CalculateLotSize(double slDistance)
{
   if(slDistance <= 0) return(0);

   double accountBalance = AccountBalance();
   double riskAmount     = accountBalance * (RiskPercent / 100.0);
   double tickValue      = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize       = MarketInfo(Symbol(), MODE_TICKSIZE);
   double lotStep        = MarketInfo(Symbol(), MODE_LOTSTEP);
   double minLot         = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot         = MathMin(MarketInfo(Symbol(), MODE_MAXLOT), MaxLotSize);

   if(tickValue <= 0 || tickSize <= 0) return(0);

   // Fórmula: Lote = RiesgoUSD / (SL_distancia / tickSize * tickValue)
   double lotSize = riskAmount / ((slDistance / tickSize) * tickValue);

   // Redondear al step permitido
   lotSize = MathFloor(lotSize / lotStep) * lotStep;

   // Aplicar límites
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return(NormalizeDouble(lotSize, 2));
}

//+------------------------------------------------------------------+
//|  OBTENER MÁXIMO DE DONCHIAN (banda superior)                      |
//|  Usa barra index=1 como referencia (vela cerrada anterior)        |
//+------------------------------------------------------------------+
double GetDonchianHigh(int period)
{
   // iHighest devuelve el índice de la vela más alta en N periodos
   // Empezamos desde index=1 para no incluir la vela actual (abierta)
   int highestBar = iHighest(NULL, 0, MODE_HIGH, period, 1);
   return High[highestBar];
}

//+------------------------------------------------------------------+
//|  OBTENER MÍNIMO DE DONCHIAN (banda inferior)                      |
//+------------------------------------------------------------------+
double GetDonchianLow(int period)
{
   int lowestBar = iLowest(NULL, 0, MODE_LOW, period, 1);
   return Low[lowestBar];
}

//+------------------------------------------------------------------+
//|  VERIFICAR SI HAY POSICIÓN ABIERTA DE ESTE EA                     |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;
      if(OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol())
         return(true);
   }
   return(false);
}

//+------------------------------------------------------------------+
//|  VERIFICAR LÍMITES DE DRAWDOWN (protección FundedNext)            |
//+------------------------------------------------------------------+
bool CheckDrawdownLimits()
{
   // Reset diario del balance de referencia
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   MqlDateTime dtLast;
   TimeToStruct(g_lastDayCheck, dtLast);

   if(dt.day != dtLast.day)
   {
      g_startBalance = AccountBalance();
      g_lastDayCheck = TimeCurrent();
   }

   // DD diario
   double dailyDD = ((g_startBalance - AccountEquity()) / g_startBalance) * 100.0;
   if(dailyDD >= MaxDailyDrawdown)
   {
      if(g_eaEnabled)
      {
         g_eaEnabled = false;
         Print("⚠️ EA DETENIDO: Daily Drawdown alcanzado (", DoubleToString(dailyDD, 2), "%)");
         CloseAllPositions();
      }
      return(false);
   }

   // DD total
   double totalDD = ((g_initBalance - AccountEquity()) / g_initBalance) * 100.0;
   if(totalDD >= MaxTotalDrawdown)
   {
      if(g_eaEnabled)
      {
         g_eaEnabled = false;
         Print("⚠️ EA DETENIDO: Total Drawdown alcanzado (", DoubleToString(totalDD, 2), "%)");
         CloseAllPositions();
      }
      return(false);
   }

   return(true);
}

//+------------------------------------------------------------------+
//|  CERRAR TODAS LAS POSICIONES ABIERTAS                             |
//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;
      if(OrderMagicNumber() != MagicNumber)           continue;
      if(OrderSymbol() != Symbol())                   continue;

      double closePrice = (OrderType() == OP_BUY) ? Bid : Ask;
      bool   result     = OrderClose(OrderTicket(), OrderLots(), closePrice, 3, clrOrange);

      if(!result)
         Print("ERROR al cerrar orden #", OrderTicket(), ": ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//|  VERIFICAR SI ESTAMOS EN SESIÓN ACTIVA                            |
//+------------------------------------------------------------------+
bool IsSessionActive()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int currentHour = dt.hour;
   return(currentHour >= SessionStartHour && currentHour < SessionEndHour);
}

//+------------------------------------------------------------------+
//|  ESCRIBIR LÍNEA EN EL ARCHIVO CSV                                 |
//+------------------------------------------------------------------+
void WriteCSVLine(datetime openTime,
                  datetime closeTime,
                  int      orderType,
                  double   openPrice,
                  double   sl,
                  double   tp,
                  double   closePrice,
                  double   profitPips,
                  double   profitUSD,
                  double   balance,
                  double   ddPct,
                  string   comment)
{
   int fileHandle = FileOpen(g_csvFileName, FILE_READ | FILE_WRITE | FILE_CSV | FILE_ANSI);
   if(fileHandle == INVALID_HANDLE)
   {
      Print("ERROR al abrir CSV para escritura: ", GetLastError());
      return;
   }

   // Moverse al final del archivo
   FileSeek(fileHandle, 0, SEEK_END);

   string orderTypeStr = (orderType == OP_BUY) ? "BUY" : "SELL";
   string timeframeStr = PeriodToString(Period());

   FileWrite(fileHandle,
             Symbol(),
             timeframeStr,
             TimeToString(openTime,  TIME_DATE | TIME_MINUTES),
             TimeToString(closeTime, TIME_DATE | TIME_MINUTES),
             orderTypeStr,
             DoubleToString(openPrice,  Digits),
             DoubleToString(sl,         Digits),
             DoubleToString(tp,         Digits),
             DoubleToString(closePrice, Digits),
             DoubleToString(profitPips, 1),
             DoubleToString(profitUSD,  2),
             DoubleToString(balance,    2),
             DoubleToString(ddPct,      2),
             comment);

   FileClose(fileHandle);
}

//+------------------------------------------------------------------+
//|  CONVERTIR PERÍODO A STRING                                       |
//+------------------------------------------------------------------+
string PeriodToString(int period)
{
   switch(period)
   {
      case PERIOD_M1:  return("M1");
      case PERIOD_M5:  return("M5");
      case PERIOD_M15: return("M15");
      case PERIOD_M30: return("M30");
      case PERIOD_H1:  return("H1");
      case PERIOD_H4:  return("H4");
      case PERIOD_D1:  return("D1");
      default:         return("CUSTOM");
   }
}

//+------------------------------------------------------------------+
//|  DESINICIALIZACIÓN                                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   Print("=== Donchian EA v1.0 Detenido ===");
   Print("Balance final: ", AccountBalance());
   Print("CSV guardado en: ", g_csvFileName);
}
