}

//+------------------------------------------------------------------+
//|  EVENTO: Orden cerrada — registrar en CSV                         |
//+------------------------------------------------------------------+
void OnTrade()
{
   if(!GenerateCSV) return;

   // Revisar historial de órdenes cerradas recientemente
