//+------------------------------------------------------------------+
//|                        Donchian_EA_v1.1.mq4                      |
//|                    Estrategia: Canal de Donchian                  |
//|                    Versión: 1.1 — Análisis Cuantitativo           |
//|   Sin circuit breaker — exposición total para observar el edge    |
//+------------------------------------------------------------------+
#property strict
#property copyright "Jose - FundedNext Development"
#property version   "1.10"

//+------------------------------------------------------------------+
//|  PARÁMETROS DE ENTRADA                                            |
//+------------------------------------------------------------------+

// --- Canal de Donchian ---
input int    DonchianPeriod   = 20;     // Periodos del canal [10-60]

// --- ATR para SL y TP dinámicos ---
input int    ATRPeriod        = 14;     // Periodos del ATR [7-21]
input double ATRMultiplierSL  = 2.0;   // Multiplicador SL [1.5-3.0]
input double ATRMultiplierTP  = 3.0;   // Multiplicador TP [2.0-4.0]

