input int    SessionStartHour = 8;     // Hora inicio (GMT)
input int    SessionEndHour   = 20;    // Hora fin (GMT)

// --- Control de dirección ---
input bool   EnableBuy        = true;  // Permitir BUY
input bool   EnableSell       = true;  // Permitir SELL

// --- CSV Export ---
