         " | TP_mult=", ATRMultiplierTP,
         " | Risk=", RiskPercent, "%");

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//|  TICK PRINCIPAL                                                    |
//+------------------------------------------------------------------+
void OnTick()
{
   // Ejecutar solo en apertura de vela nueva
   static datetime lastBar = 0;
   if(Time[0] == lastBar) return;
   lastBar = Time[0];

   // Filtro de sesión (desactivado por defecto en análisis)
   if(UseSessionFilter && !IsSessionActive()) return;

   // Una sola posición a la vez
   if(HasOpenPosition()) return;

   // --- Valores del Canal de Donchian sobre velas cerradas ---
   // index=1: no incluye la vela actual para evitar lookahead bias
   double upperBand = GetDonchianHigh(DonchianPeriod);
   double lowerBand = GetDonchianLow(DonchianPeriod);

   // --- ATR de la vela anterior ---
   double atr = iATR(NULL, 0, ATRPeriod, 1);
   if(atr <= 0) return;

   double slDist = atr * ATRMultiplierSL;
   double tpDist = atr * ATRMultiplierTP;

   // --- SEÑAL BUY: cierre anterior por encima del máximo Donchian ---
   if(EnableBuy && Close[1] > upperBand)
   {
      double entryPrice = Ask;
      double sl         = entryPrice - slDist;
      double tp         = entryPrice + tpDist;
      double lot        = GetLotSize(slDist);

      if(lot <= 0) return;

      int ticket = OrderSend(Symbol(), OP_BUY, lot,
                             entryPrice, 3,
                             NormalizeDouble(sl, Digits),
                             NormalizeDouble(tp, Digits),
                             "DCH_BUY", MagicNumber, 0, clrDodgerBlue);
      if(ticket < 0)
         Print("ERROR BUY: ", GetLastError());
   }

   // --- SEÑAL SELL: cierre anterior por debajo del mínimo Donchian ---
   else if(EnableSell && Close[1] < lowerBand)
   {
      double entryPrice = Bid;
      double sl         = entryPrice + slDist;
      double tp         = entryPrice - tpDist;
      double lot        = GetLotSize(slDist);

      if(lot <= 0) return;

      int ticket = OrderSend(Symbol(), OP_SELL, lot,
                             entryPrice, 3,
                             NormalizeDouble(sl, Digits),
                             NormalizeDouble(tp, Digits),
                             "DCH_SELL", MagicNumber, 0, clrCrimson);
      if(ticket < 0)
         Print("ERROR SELL: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//|  EVENTO TRADE — Registrar cierre en CSV                           |
//+------------------------------------------------------------------+
void OnTrade()
{
   if(!GenerateCSV) return;

   for(int i = OrdersHistoryTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_HISTORY)) continue;
      if(OrderMagicNumber() != MagicNumber)             continue;
      if(OrderSymbol()      != Symbol())                continue;

      // Solo órdenes cerradas en los últimos 5 segundos
      if(TimeCurrent() - OrderCloseTime() > 5)          continue;

      // Pip size: 5 dígitos = 0.0001, 4 dígitos = 0.001
      double pipSize    = (Digits == 5 || Digits == 3) ? 0.0001 : 0.001;
      double profitPips = 0;

      if(OrderType() == OP_BUY)
         profitPips = (OrderClosePrice() - OrderOpenPrice()) / pipSize;
      else if(OrderType() == OP_SELL)
         profitPips = (OrderOpenPrice() - OrderClosePrice()) / pipSize;

      // Drawdown relativo al balance inicial del backtest
      double ddPct = ((g_initBalance - AccountBalance()) / g_initBalance) * 100.0;
      if(ddPct < 0) ddPct = 0;

      double netProfit = OrderProfit() + OrderSwap() + OrderCommission();

      WriteCSVLine(
         OrderOpenTime(),   OrderCloseTime(),
         OrderType(),
         OrderOpenPrice(),  OrderStopLoss(), OrderTakeProfit(), OrderClosePrice(),
         profitPips,        netProfit,
         AccountBalance(),  ddPct,
         OrderComment()
      );
   }
}

//+------------------------------------------------------------------+
//|  CALCULAR LOTE                                                     |
//+------------------------------------------------------------------+
double GetLotSize(double slDistance)
{
   if(UseFixedLot) return(NormalizeDouble(FixedLotSize, 2));

   if(slDistance <= 0) return(0);

   double balance   = AccountBalance();
   double riskUSD   = balance * (RiskPercent / 100.0);
   double tickVal   = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSz    = MarketInfo(Symbol(), MODE_TICKSIZE);
   double lotStep   = MarketInfo(Symbol(), MODE_LOTSTEP);
   double minLot    = MarketInfo(Symbol(), MODE_MINLOT);
