      StringReplace(g_csvFileName, ":", "-");
      StringReplace(g_csvFileName, " ", "_");

      int fh = FileOpen(g_csvFileName, FILE_WRITE | FILE_CSV | FILE_ANSI);
      if(fh != INVALID_HANDLE)
      {
         FileWrite(fh,
                   "Ticker","Timeframe",
                   "FechaHoraApertura","FechaHoraCierre",
                   "TipoOrden",
                   "PrecioEntrada","StopLoss","TakeProfit","PrecioSalida",
                   "ProfitPips","ProfitUSD",
