                   "DonchianPeriod","ATRMultSL","ATRMultTP",
                   "Comentario");
         FileClose(fh);
         Print("CSV inicializado: ", g_csvFileName);
      }
      else
         Print("ERROR CSV — código: ", GetLastError());
   }

   Print("=== Donchian EA v1.1 [ANALYSIS MODE] ===");
   Print("Par: ", Symbol(), " | TF: ", PeriodToString(Period()));
   Print("Donchian=", DonchianPeriod,
         " | SL_mult=", ATRMultiplierSL,
         " | TP_mult=", ATRMultiplierTP,
         " | Risk=", RiskPercent, "%");

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//|  TICK PRINCIPAL                                                    |
//+------------------------------------------------------------------+
void OnTick()
{
   // Ejecutar solo en apertura de vela nueva
   static datetime lastBar = 0;
   if(Time[0] == lastBar) return;
   lastBar = Time[0];

   // Filtro de sesión (desactivado por defecto en análisis)
   if(UseSessionFilter && !IsSessionActive()) return;

   // Una sola posición a la vez
   if(HasOpenPosition()) return;

   // --- Valores del Canal de Donchian sobre velas cerradas ---
   // index=1: no incluye la vela actual para evitar lookahead bias
   double upperBand = GetDonchianHigh(DonchianPeriod);
   double lowerBand = GetDonchianLow(DonchianPeriod);

   // --- ATR de la vela anterior ---
   double atr = iATR(NULL, 0, ATRPeriod, 1);
   if(atr <= 0) return;

   double slDist = atr * ATRMultiplierSL;
   double tpDist = atr * ATRMultiplierTP;

   // --- SEÑAL BUY: cierre anterior por encima del máximo Donchian ---
   if(EnableBuy && Close[1] > upperBand)
   {
      double entryPrice = Ask;
      double sl         = entryPrice - slDist;
      double tp         = entryPrice + tpDist;
      double lot        = GetLotSize(slDist);

      if(lot <= 0) return;

      int ticket = OrderSend(Symbol(), OP_BUY, lot,
                             entryPrice, 3,
                             NormalizeDouble(sl, Digits),
                             NormalizeDouble(tp, Digits),
                             "DCH_BUY", MagicNumber, 0, clrDodgerBlue);
      if(ticket < 0)
         Print("ERROR BUY: ", GetLastError());
   }

   // --- SEÑAL SELL: cierre anterior por debajo del mínimo Donchian ---
   else if(EnableSell && Close[1] < lowerBand)
   {
      double entryPrice = Bid;
      double sl         = entryPrice + slDist;
      double tp         = entryPrice - tpDist;
      double lot        = GetLotSize(slDist);

      if(lot <= 0) return;

      int ticket = OrderSend(Symbol(), OP_SELL, lot,
                             entryPrice, 3,
                             NormalizeDouble(sl, Digits),
                             NormalizeDouble(tp, Digits),
                             "DCH_SELL", MagicNumber, 0, clrCrimson);
      if(ticket < 0)
         Print("ERROR SELL: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
