void OnTrade()
{
   if(!GenerateCSV) return;

   for(int i = OrdersHistoryTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_HISTORY)) continue;
      if(OrderMagicNumber() != MagicNumber)             continue;
      if(OrderSymbol()      != Symbol())                continue;

      // Solo órdenes cerradas en los últimos 5 segundos
      if(TimeCurrent() - OrderCloseTime() > 5)          continue;

      // Pip size: 5 dígitos = 0.0001, 4 dígitos = 0.001
      double pipSize    = (Digits == 5 || Digits == 3) ? 0.0001 : 0.001;
      double profitPips = 0;

      if(OrderType() == OP_BUY)
         profitPips = (OrderClosePrice() - OrderOpenPrice()) / pipSize;
      else if(OrderType() == OP_SELL)
         profitPips = (OrderOpenPrice() - OrderClosePrice()) / pipSize;

      // Drawdown relativo al balance inicial del backtest
      double ddPct = ((g_initBalance - AccountBalance()) / g_initBalance) * 100.0;
      if(ddPct < 0) ddPct = 0;

      double netProfit = OrderProfit() + OrderSwap() + OrderCommission();

      WriteCSVLine(
         OrderOpenTime(),   OrderCloseTime(),
         OrderType(),
         OrderOpenPrice(),  OrderStopLoss(), OrderTakeProfit(), OrderClosePrice(),
         profitPips,        netProfit,
         AccountBalance(),  ddPct,
         OrderComment()
      );
   }
}

